#!/usr/bin/env node
import{readFileSync}from"node:fs";import{dirname,join}from"node:path";import{fileURLToPath}from"node:url";import{customAlphabet,nanoid}from"../index.js";function print(e){process.stdout.write(e+"\n")}function error(e){process.stderr.write(e+"\n"),process.exit(1)}if(process.argv.includes("--version")||process.argv.includes("-v")){let e=dirname(fileURLToPath(import.meta.url));print(JSON.parse(readFileSync(join(e,"..","package.json"),"utf8")).version),process.exit()}let alphabet,size;(process.argv.includes("--help")||process.argv.includes("-h"))&&(print("Usage\n  $ nanoid [options]\n\nOptions\n  -s, --size       Generated ID size\n  -a, --alphabet   Alphabet to use\n  -v, --version    Show version number\n  -h, --help       Show this help\n\nExamples\n  $ nanoid -s 15\n  S9sBF77U6sDB8Yg\n\n  $ nanoid --size 10 --alphabet abc\n  bcabababca"),process.exit());for(let e=2;e<process.argv.length;e++){let s=process.argv[e];"--size"===s||"-s"===s?(size=Number(process.argv[e+1]),e+=1,(Number.isNaN(size)||size<=0)&&error("Size must be positive integer")):"--alphabet"===s||"-a"===s?(alphabet=process.argv[e+1],e+=1):error("Unknown argument "+s)}if(alphabet){print(customAlphabet(alphabet,size)())}else print(nanoid(size));